                  .HasJsonPropertyName("id")
                  .ToJsonProperty("id");

            // Breaking change 3: Cosmos DB does not support indexes defined via EF Core.
            // HasIndex() now throws at model validation in EF Core 9.
            // Removed: entity.HasIndex(b => b.Name);
        });
    }
}
