using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF Core 9 renamed the discriminator JSON property
            // from "Discriminator" to "$type". Existing documents use "Discriminator".
            entity.HasDiscriminator<string>("Discriminator");
            entity.Property<string>("Discriminator").ToJsonProperty("Discriminator");

            // Breaking change 2: EF Core 9 changed the Cosmos "id" value format
            // from "EntityType|KeyValue" (e.g. "Blog|1") to just "KeyValue".
            // Existing documents and raw SQL queries use the old format.
            // Preserve it by mapping Id through a value converter.
            entity.Property(b => b.Id)
                  .HasConversion(
                      appValue => "Blog|" + appValue,
                      storeValue => storeValue.StartsWith("Blog|")
                          ? storeValue.Substring("Blog|".Length)
                          : storeValue);

            // Breaking change 3: HasIndex() on Cosmos entities was silently ignored
            // in EF 8 but now throws InvalidOperationException in EF 9.
            // Removed: entity.HasIndex(b => b.Name);
            // Manage indexes via Azure Portal / Cosmos indexing policy instead.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

