using System.Linq;

class SyncJob
{
    void Run(BlogContext context)
    {
        // Breaking change 4: EF Core 9 Cosmos uses patch-based (partial) updates by default,
        // sending only modified properties instead of replacing the full document.
        // This is more efficient but be aware of the behavioral difference.
        var blogs = context.Blogs.ToList();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        context.SaveChanges();
    }
}

